#include <stdio.h>
#include <string.h>
int main() {
    int T, N;
    char S[10], B[55];
    scanf("%d", &T);
    while (T--) {
        scanf("%d %s", &N, S);
        int sum0 = 0, sum1 = 0;
        for (int i = 0; i < N; i++) {
            scanf("%s", B);
            int len = strlen(B);
            int count0 = 0, count1 = 0;
            for (int j = 0; j < len; j++) {
                if (B[j] == '0') count0++;
                else count1++;
            }
            sum0 ^= count0;
            sum1 ^= count1;
        }
        if (strcmp(S, "Dee") == 0) {
            if (sum0 == 0 && sum1 == 0) printf("Dee\n");
            else printf("Dum\n");
        } else {
            if (sum0 == 0 && sum1 == 0) printf("Dum\n");
            else printf("Dee\n");
        }
    }
    return 0;
}

