import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            String S = sc.next();
            int sum0 = 0, sum1 = 0;
            for (int i = 0; i < N; i++) {
                String B = sc.next();
                int len = B.length();
                int count0 = 0, count1 = 0;
                for (int j = 0; j < len; j++) {
                    if (B.charAt(j) == '0') count0++;
                    else count1++;
                }
                sum0 ^= count0;
                sum1 ^= count1;
            }
            if (S.equals("Dee")) {
                if (sum0 == 0 && sum1 == 0) System.out.println("Dee");
                else System.out.println("Dum");
            } else {
                if (sum0 == 0 && sum1 == 0) System.out.println("Dum");
                else System.out.println("Dee");
            }
        }
    }
}

